/** Original PRISM triangle + wordmark for native shell terminal. */
export function printPrismLogoAscii() {
    return [
        "",
        "            ▲",
        "           ╱ ╲",
        "          ╱   ╲",
        "         ╱     ╲",
        "        ╱───────╲",
        "       PRISM",
        "",
    ].join("\n");
}
